<script type="text/javascript">
$j(function() {
  var displayTemplatew8 = htmlForm.compileMustacheTemplate('{{name}}');
  var valueTemplatew8 = htmlForm.compileMustacheTemplate('Drug:{{id}}');
  $j('#w8-display').autocomplete({
    source: '/openmrs/module/htmlformentry/drugSearch.form',
    minLength: 2,
    focus: function(event, ui) {
      if (ui.item.name != 'No results') {
         $j('#w8-display').val(displayTemplatew8(ui.item));
      } else {
         $j('#w8-value').val('');
      }
      return false;
    },
    select: function(event, ui) {
      if (ui.item.name != 'No results') {
         $j('#w8-display').val(displayTemplatew8(ui.item));
         $j('#w8-value').val(valueTemplatew8(ui.item));
         if (ui.item.retired) {
             $j('#w8-display').css('color', 'gray');
             $j('#w8-display').css('font-style', 'italic');

         } else { 
             $j('#w8-display').css('color', '');
             $j('#w8-display').css('font-style', '');
         }
      } else {
         $j('#w8-value').val('');
      }
      return false;    },
    change: function(event, ui) {
      if (!ui.item) {
         $j('#w8-value').val('');
      }
    },
    response: function(event, ui) {
      var results = ui.content;
      if (results.length === 0) {
         results.push({ value: '', name: 'No results', label: '' });
      }
    }
  })
  .data('ui-autocomplete')._renderItem = function(ul, item) {
    var anchorItem = $j('<a>' + displayTemplatew8(item) + '</a>');
    if(item.retired) { ;
         anchorItem.css('color', 'gray');
         anchorItem.css('font-style', 'italic');
    }
    var listItem = $j('<li>').data('autocomplete-item', item).append(anchorItem).appendTo(ul);
    return listItem;
  };
});
</script>
